cuda_source = r"""
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <cstdint>

__global__ void scalar_mul_float4_kernel(const float4* __restrict__ in,
                                         float4* __restrict__ out,
                                         float s,
                                         int64_t n4) {
    int64_t idx = (int64_t)blockIdx.x * blockDim.x + threadIdx.x;
    int64_t stride = (int64_t)blockDim.x * gridDim.x;

    for (int64_t i = idx; i < n4; i += stride) {
        float4 v = in[i];
        v.x *= s;
        v.y *= s;
        v.z *= s;
        v.w *= s;
        out[i] = v;
    }
}

__global__ void scalar_mul_float_kernel(const float* __restrict__ in,
                                        float* __restrict__ out,
                                        float s,
                                        int64_t n) {
    int64_t idx = (int64_t)blockIdx.x * blockDim.x + threadIdx.x;
    int64_t stride = (int64_t)blockDim.x * gridDim.x;

    for (int64_t i = idx; i < n; i += stride) {
        out[i] = in[i] * s;
    }
}

torch::Tensor scalar_mul_cuda(torch::Tensor A, double s) {
    TORCH_CHECK(A.is_cuda(), "A must be a CUDA tensor");
    TORCH_CHECK(A.scalar_type() == torch::kFloat32, "A must be float32");

    auto C = torch::empty_like(A);
    int64_t n = A.numel();
    if (n == 0) return C;

    const float* in = A.data_ptr<float>();
    float* out = C.data_ptr<float>();
    float sf = static_cast<float>(s);

    const int threads = 256;
    int blocks;

    bool can_vec4 = A.is_contiguous() && C.is_contiguous() &&
                    ((reinterpret_cast<uintptr_t>(in) & 15) == 0) &&
                    ((reinterpret_cast<uintptr_t>(out) & 15) == 0) &&
                    ((n & 3) == 0);

    if (can_vec4) {
        int64_t n4 = n >> 2;
        blocks = (int)((n4 + threads - 1) / threads);
        blocks = blocks > 65535 ? 65535 : blocks;
        scalar_mul_float4_kernel<<<blocks, threads>>>(
            reinterpret_cast<const float4*>(in),
            reinterpret_cast<float4*>(out),
            sf,
            n4
        );
    } else {
        blocks = (int)((n + threads - 1) / threads);
        blocks = blocks > 65535 ? 65535 : blocks;
        scalar_mul_float_kernel<<<blocks, threads>>>(in, out, sf, n);
    }

    return C;
}
