#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

// Global cuBLAS handle
static cublasHandle_t handle = nullptr;

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    TORCH_CHECK(A.device().is_cuda(), "A must be a CUDA tensor");
    TORCH_CHECK(B.device().is_cuda(), "B must be a CUDA tensor");
    TORCH_CHECK(A.is_contiguous(), "A must be contiguous");
    TORCH_CHECK(B.is_contiguous(), "B must be contiguous");
    TORCH_CHECK(A.dtype() == torch::kFloat32, "A must be float32");
    TORCH_CHECK(B.dtype() == torch::kFloat32, "B must be float32");

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    TORCH_CHECK(B.size(0) == K, "Matrix dimensions must match");

    auto C = torch::empty({M, N}, A.options());

    // Initialize cuBLAS handle if needed
    if (handle == nullptr) {
        cublasCreate(&handle);
        // Use tensor cores if available
        cublasSetMathMode(handle, CUBLAS_DEFAULT_MATH);
    }

    const float alpha = 1.0f;
    const float beta = 0.0f;

    // cuBLAS uses column-major order, so we compute C^T = B^T * A^T
    // which gives us C in row-major order
    // C (M x N) = A (M x K) * B (K x N)
    // In column-major: C^T (N x M) = B^T (N x K) * A^T (K x M)

    cublasStatus_t status = cublasSgemm(
        handle,
        CUBLAS_OP_N,      // B is not transposed (but treated as B^T in col-major)
        CUBLAS_OP_N,      // A is not transposed (but treated as A^T in col-major)
        N,                // rows of op(B^T) = N
        M,                // cols of op(A^T) = M  
        K,                // shared dimension
        &alpha,
        B.data_ptr<float>(), N,   // B with leading dim N
        A.data_ptr<float>(), K,   // A with leading dim K
        &beta,
        C.data_ptr<float>(), N    // C with leading dim N
    );

    TORCH_CHECK(status == CUBLAS_STATUS_SUCCESS, "cuBLAS sgemm failed");

    return C;
}
