    const int NUM_THREADS = THREADS_X * THREADS_Y;  // 256
    const int threadId = ty * THREADS_X + tx;

    __shared__ float As[BM][BK];
    __shared__ float Bs[BK][BN];

    float Creg[TM][TN] = {0.0f};

    const int row_start = by * BM + ty * TM;
    const int col_start = bx * BN + tx * TN;

    // Elements to load per thread for A: (BM * BK) / NUM_THREADS = 128*16/256 = 8
    // Elements to load per thread for B: (BK * BN) / NUM_THREADS = 16*128/256 = 8

    const int A_loads = (BM * BK) / NUM_THREADS;
    const int B_loads = (BK * BN) / NUM_THREADS;

    for (int kt = 0; kt < K; kt += BK) {
        // Load A tile: BM x BK
        #pragma unroll
        for (int load = 0; load < A_loads; load++) {
            int idx = threadId + load * NUM_THREADS;
            int a_row = idx / BK;
            int a_col = idx % BK;
            int global_row = by * BM + a_row;
            int global_col = kt + a_col;

            if (global_row < M && global_col < K) {
                As[a_row][a_col] = A[global_row * K + global_col];
            } else {
                As[a_row][a_col] = 0.0f;
            }
        }

        // Load B tile: BK x BN
        #pragma unroll
        for (int load = 0; load < B_loads; load++) {
            int idx = threadId + load * NUM_THREADS;
            int b_row = idx / BN;
            int b_col = idx % BN;
            int global_row = kt + b_row;
            int global_col = bx * BN + b_col;

            if (global_row < K && global_col < N) {
                Bs[b_row][b_col] = B[global_row * N + global_col];
            } else {
                Bs[b_row][b_col] = 0.0f;
            }
        }

        __syncthreads();

        // Compute
        #pragma unroll
        for (int k = 0; k < BK; k++) {
            float Areg[TM];
            float Breg[TN];

            #pragma unroll
            for (int i = 0; i < TM; i++) {
                Areg[i] = As[ty * TM + i][k];
