// Use cuBLAS for optimal performance - this is what PyTorch uses under the hood
// but we can call it directly with less overhead

static cublasHandle_t handle = nullptr;

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    TORCH_CHECK(A.is_cuda(), "A must be a CUDA tensor");
    TORCH_CHECK(B.is_cuda(), "B must be a CUDA tensor");
    TORCH_CHECK(A.is_contiguous(), "A must be contiguous");
    TORCH_CHECK(B.is_contiguous(), "B must be contiguous");
    TORCH_CHECK(A.dtype() == torch::kFloat32, "A must be float32");
    TORCH_CHECK(B.dtype() == torch::kFloat32, "B must be float32");

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    auto C = torch::empty({M, N}, A.options());

    if (handle == nullptr) {
        cublasCreate(&handle);
        cublasSetMathMode(handle, CUBLAS_DEFAULT_MATH);
    }

    const float alpha = 1.0f;
    const float beta = 0.0f;

    // cuBLAS uses column-major, so we compute B^T * A^T = (A * B)^T
    // which gives us C in row-major format
    // Or equivalently: C = A * B in row-major is C^T = B^T * A^T in column-major
    // cublasSgemm does: C = alpha * op(A) * op(B) + beta * C
