    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Each block computes a BM x BN tile of C
    // Each thread computes a TM x TN sub-tile
    // Block has (BM/TM) x (BN/TN) = 16 x 16 = 256 threads

    // Shared memory for tiles of A and B
    __shared__ float As[BK][BM];
    __shared__ float Bs[BK][BN];

    // Registers for the thread's output tile
    float Creg[TM][TN] = {0.0f};

    // Registers for loading A and B tiles
    float Areg[TM];
    float Breg[TN];

    // Starting row and col for this thread's tile in C
    int row_start = by * BM + ty * TM;
    int col_start = bx * BN + tx * TN;

