import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Warp reduce using shuffle
__inline__ __device__ float warpReduceSum(float val) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset /= 2)
        val += __shfl_down_sync(0xffffffff, val, offset);
    return val;
}

// Block reduce
__inline__ __device__ float blockReduceSum(float val) {
    __shared__ float shared[32];
    int lane = threadIdx.x & 31;
    int wid = threadIdx.x >> 5;

    val = warpReduceSum(val);

    if (lane == 0) shared[wid] = val;
    __syncthreads();

    int numWarps = blockDim.x >> 5;
    val = (threadIdx.x < numWarps) ? shared[lane] : 0.0f;

    if (wid == 0) val = warpReduceSum(val);

    return val;
}

// Multi-block per row kernel for better parallelism
// Each block handles a chunk of the row, results are atomically added
__global__ void matvec_kernel_multiblock(const float* __restrict__ A, 
                                          const float* __restrict__ B,
                                          float* __restrict__ C,
                                          int M, int K, int blocksPerRow) {
    int row = blockIdx.x / blocksPerRow;
    int blockInRow = blockIdx.x % blocksPerRow;

    if (row >= M) return;

    int chunkSize = (K + blocksPerRow - 1) / blocksPerRow;
    int startIdx = blockInRow * chunkSize;
    int endIdx = min(startIdx + chunkSize, K);

    const float* A_row = A + row * K;

    float sum = 0.0f;

    // Process 4 elements at a time when possible
    int i = startIdx + threadIdx.x;
    int stride = blockDim.x;

    // Unrolled loop for better instruction-level parallelism
    for (; i + 3 * stride < endIdx; i += 4 * stride) {
        sum += A_row[i] * __ldg(&B[i]);
        sum += A_row[i + stride] * __ldg(&B[i + stride]);
        sum += A_row[i + 2*stride] * __ldg(&B[i + 2*stride]);
        sum += A_row[i + 3*stride] * __ldg(&B[i + 3*stride]);
    }

    // Handle remaining elements
    for (; i < endIdx; i += stride) {
        sum += A_row[i] * __ldg(&B[i]);
    }

    sum = blockReduceSum(sum);

    if (threadIdx.x == 0) {
        atomicAdd(&C[row], sum);
    }
}

// Single block per row with float4 vectorization
__global__ void matvec_kernel_vec4(const float4* __restrict__ A4, 
                                    const float4* __restrict__ B4,
                                    float* __restrict__ C,
                                    int M, int K4) {
    int row = blockIdx.x;
    if (row >= M) return;

    const float4* A_row = A4 + row * K4;

    float sum = 0.0f;

    int i = threadIdx.x;
    int stride = blockDim.x;

    // Unroll by 4 for better ILP
    for (; i + 3 * stride < K4; i += 4 * stride) {
        float4 a0 = A_row[i];
        float4 b0 = __ldg(&B4[i]);
        float4 a1 = A_row[i + stride];
        float4 b1 = __ldg(&B4[i + stride]);
        float4 a2 = A_row[i + 2*stride];
        float4 b2 = __ldg(&B4[i + 2*stride]);
        float4 a3 = A_row[i + 3*stride];
        float4 b3 = __ldg(&B4[i + 3*stride]);

        sum += a0.x * b0.x + a0.y * b0.y + a0.z * b0.z + a0.w * b0.w;
        sum += a1.x * b1.x + a1.y * b1.y + a1.z * b1.z + a1.w * b1.w;
        sum += a2.x * b2.x + a2.y * b2.y + a2.z * b2.z + a2.w * b2.w;
        sum += a3.x * b3.x + a3.y * b3.y + a3.z * b3.z + a3.w * b3.w;
    }

    for (; i < K4; i += stride) {
        float4 a = A_row[i];
        float4 b = __ldg(&B4[i]);
        sum += a.x * b.x + a.y * b.y + a.z * b.z + a.w * b.w;
    }

    sum = blockReduceSum(sum);

    if (threadIdx.x == 0) {
        C[row] = sum;
    }
}

torch::Tensor matvec_cuda(torch::Tensor A, torch::Tensor B) {
    int M = A.size(0);
    int K = A.size(1);

    auto C = torch::zeros({M, 1}, A.options());

    const int threadsPerBlock = 256;

    // For very large K, use multiple blocks per row
    if (K > 262144) {
        int blocksPerRow = 4;  // Split each row across 4 blocks
        int totalBlocks = M * blocksPerRow;

        matvec_kernel_multiblock<<<totalBlocks, threadsPerBlock>>>(
            A.data_ptr<float>(),
            B.data_ptr<float>(),
            C.data_ptr<float>(),
            M, K, blocksPerRow
        );
    } else if (K % 4 == 0) {
        int K4 = K / 4;
        matvec_kernel_vec4<<<M, threadsPerBlock>>>(
            reinterpret_cast<const float4*>(A.data_ptr<float>()),
            reinterpret_cast<const float4*>(B.data_ptr<float>()),
            C.data_ptr<float>(),
            M, K4
        );
