The best approach is to use cuBLAS directly through the CUDA runtime, which is what PyTorch uses internally but with some overhead. By calling cuBLAS directly, we can potentially reduce overhead while still getting the optimized GEMM implementation.

```python
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

// Global cuBLAS handle for reuse
static cublasHandle_t handle = nullptr;

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    TORCH_CHECK(A.is_cuda(), "A must be a CUDA tensor");
    TORCH_CHECK(B.is_cuda(), "B must be a CUDA tensor");
    TORCH_CHECK(A.scalar_type() == torch::kFloat32, "A must be float32");
    TORCH_CHECK(B.scalar_type() == torch::kFloat32, "B must be float32");

    // Ensure contiguous
    A = A.contiguous();
    B = B.contiguous();

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    TORCH_CHECK(B.size(0) == K, "Matrix dimensions must match");

    auto C = torch::empty({M, N}, A.options());

    // Initialize cuBLAS handle if needed
    if (handle == nullptr) {
        cublasCreate(&handle);
        // Use Tensor Cores if available
        cublasSetMathMode(handle, CUBLAS_DEFAULT_MATH);
    }

    const float alpha = 1.0f;
    const float beta = 0.0f;

    // cuBLAS uses column-major order, so we compute C^T = B^T * A^T
    // which gives us C in row-major order
    // C (M x N) = A (M x K) * B (K x N)
    // In column-major: C^T (N x M) = B^T (N x K) * A^T (K x M)

    cublasStatus_t status = cublasSgemm(
        handle,
        CUBLAS_OP_N,    // B is not transposed (but we're treating row-major as col-major)
        CUBLAS_OP_N,    // A is not transposed
        N,              // rows of op(B) and C
        M,              // cols of op(A) and C  
        K,              // cols of op(B), rows of op(A)
        &alpha,
        B.data_ptr<float>(), N,   // B with leading dimension N
        A.data_ptr<float>(), K,   // A with leading dimension K
        &beta,
        C.data_ptr<float>(), N    // C with leading dimension N
    );

    TORCH_CHECK(status == CUBLAS_STATUS_SUCCESS, "cuBLAS SGEMM failed");

    return C;
