    __shared__ float Bs[BLOCK_K][TILE_N + 1];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int row_base = by * TILE_M;
    const int col_base = bx * TILE_N;

    // Thread ID within block
    const int tid = ty * blockDim.x + tx;
    const int num_threads = blockDim.x * blockDim.y;

    // Load A tile (TILE_M x K) into shared memory
    for (int i = tid; i < TILE_M * K; i += num_threads) {
        int r = i / K;
        int c = i % K;
        int global_row = row_base + r;
        if (global_row < M && c < K) {
            As[r][c] = A[global_row * K + c];
        } else {
            As[r][c] = 0.0f;
        }
    }

    // Load B tile (K x TILE_N) into shared memory
    for (int i = tid; i < K * TILE_N; i += num_threads) {
        int r = i / TILE_N;
        int c = i % TILE_N;
        int global_col = col_base + c;
        if (r < K && global_col < N) {
            Bs[r][c] = B[r * N + global_col];
        } else {
            Bs[r][c] = 0.0f;
        }
