    const int row_offset = ty * 4;
    const int col_offset = tx * 4;

    float acc[4][4] = {{0.0f}};

    // Compute the dot products
    #pragma unroll
    for (int k = 0; k < BLOCK_K; k++) {
        float a_vals[4];
        float b_vals[4];

        #pragma unroll
        for (int i = 0; i < 4; i++) {
            a_vals[i] = As[row_offset + i][k];
            b_vals[i] = Bs[k][col_offset + i];
