// Optimized kernel for tall-skinny matmul where K is small
// A: (M, K), B: (K, N), C: (M, N) where K is small (32)
__global__ void tall_skinny_matmul_kernel(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    const int M,
    const int N,
    const int K
) {
    // Each block computes a TILE_M x TILE_N tile of C
    // We use shared memory to cache the entire K dimension since K is small

    __shared__ float As[TILE_M][BLOCK_K + 1];  // +1 to avoid bank conflicts
    __shared__ float Bs[BLOCK_K][TILE_N + 1];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = blockIdx.x;
    const int by = blockIdx.y;

    const int row_base = by * TILE_M;
    const int col_base = bx * TILE_N;

    // Thread ID within block
    const int tid = ty * blockDim.x + tx;
    const int num_threads = blockDim.x * blockDim.y;

    // Load A tile (TILE_M x K) into shared memory
    for (int i = tid; i < TILE_M * K; i += num_threads) {
        int r = i / K;
        int c = i % K;
        int global_row = row_base + r;
        if (global_row < M && c < K) {
            As[r][c] = A[global_row * K + c];
        } else {
            As[r][c] = 0.0f;
        }
    }

    // Load B tile (K x TILE_N) into shared memory
    for (int i = tid; i < K * TILE_N; i += num_threads) {
        int r = i / TILE_N;
        int c = i % TILE_N;
        int global_col = col_base + c;
        if (r < K && global_col < N) {
            Bs[r][c] = B[r * N + global_col];
        } else {
            Bs[r][c] = 0.0f;
        }
    }

    __syncthreads();

    // Each thread computes a 4x4 sub-tile
    const int row_offset = ty * 4;
    const int col_offset = tx * 4;

    float acc[4][4] = {{0.0f}};

    // Compute the dot products
    #pragma unroll
    for (int k = 0; k < BLOCK_K; k++) {
        float a_vals[4];
        float b_vals[4];

        #pragma unroll
        for (int i = 0; i < 4; i++) {
            a_vals[i] = As[row_offset + i][k];
            b_vals[i] = Bs[k][col_offset + i];
        }

        #pragma unroll
        for (int i = 0; i < 4; i++) {
            #pragma unroll
            for (int j = 0; j < 4; j++) {
                acc[i][j] += a_vals[i] * b_vals[j];
            }
        }
    }

    // Write results back to global memory
    #pragma unroll
    for (int i = 0; i < 4; i++) {
        int global_row = row_base + row_offset + i;
        if (global_row < M) {
            #pragma unroll
            for (int j = 0; j < 4; j++) {
                int global_col = col_base + col_offset + j;
                if (global_col < N) {
                    C[global_row * N + global_col] = acc[i][j];
                }
            }
        }
    }
