__global__ void diag_matmul_kernel_vectorized(const float* __restrict__ A, 
                                               const float* __restrict__ B, 
                                               float* __restrict__ C,
                                               int N, int M) {
    // Process 4 elements at a time using float4
    int idx = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    int total = N * M;

    if (idx + 3 < total) {
        int row = idx / M;
        float a_val = A[row];

        // Check if all 4 elements are in the same row
        int row_end = (idx + 3) / M;

        if (row == row_end) {
            // All 4 elements in same row, can use vectorized load/store
            float4 b_vals = *reinterpret_cast<const float4*>(B + idx);
            float4 c_vals;
            c_vals.x = a_val * b_vals.x;
            c_vals.y = a_val * b_vals.y;
            c_vals.z = a_val * b_vals.z;
            c_vals.w = a_val * b_vals.w;
            *reinterpret_cast<float4*>(C + idx) = c_vals;
        } else {
            // Elements span multiple rows, process individually
            for (int i = 0; i < 4 && idx + i < total; i++) {
                int curr_row = (idx + i) / M;
                C[idx + i] = A[curr_row] * B[idx + i];
