    // C[i][j] = sum(A[i][k] * B[k][j]) for k from j to i
    // Since A is lower triangular: A[i][k] = 0 for k > i
    // Since B is lower triangular: B[k][j] = 0 for j > k
    // So we only need k from j to i (where j <= k <= i)

    int numTiles = (N + TILE_SIZE - 1) / TILE_SIZE;

    for (int t = 0; t < numTiles; t++) {
        int tileStart = t * TILE_SIZE;

        // Load tile of A
        int aCol = tileStart + threadIdx.x;
        if (row < N && aCol < N) {
