Let me create a hybrid approach that uses cuBLAS for the heavy lifting:

```python
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

#define BLOCK_SIZE 256

// Kernel to zero out the upper triangular part
__global__ void apply_tril_mask_kernel(float* C, int N) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * N;

    while (idx < total) {
        int row = idx / N;
        int col = idx % N;

        if (col > row) {
            C[idx] = 0.0f;
        }

        idx += blockDim.x * gridDim.x;
    }
}

// More efficient kernel that only processes upper triangular elements
__global__ void zero_upper_triangular(float* C, int N) {
    // Each thread handles one element in the upper triangular part
    // We have N*(N-1)/2 elements in the strict upper triangular part

    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Total upper triangular elements (excluding diagonal)
    long long total_upper = ((long long)N * (N - 1)) / 2;

    if (idx < total_upper) {
        // Convert linear index to (row, col) in upper triangular
        // For upper triangular, row < col
        // Elements are ordered: (0,1), (0,2), ..., (0,N-1), (1,2), (1,3), ..., (N-2,N-1)

        // Find row: row r has (N-1-r) elements
        // Cumulative elements up to row r: r*N - r*(r+1)/2
        // We need to find r such that r*N - r*(r+1)/2 <= idx < (r+1)*N - (r+1)*(r+2)/2

        // Using quadratic formula to find row
        // idx = r*N - r*(r+1)/2 + (col - r - 1)
        // Approximate: r ≈ N - 0.5 - sqrt((N-0.5)^2 - 2*idx)

        float n = (float)N;
        float discriminant = (n - 0.5f) * (n - 0.5f) - 2.0f * idx;
        int row = (int)(n - 0.5f - sqrtf(discriminant));

        // Clamp row to valid range
        if (row < 0) row = 0;
        if (row >= N - 1) row = N - 2;

        // Calculate start index for this row
        long long row_start = (long long)row * N - ((long long)row * (row + 1)) / 2;

        // Adjust row if needed
        while (row_start > idx && row > 0) {
            row--;
            row_start = (long long)row * N - ((long long)row * (row + 1)) / 2;
        }
        while (row < N - 1) {
            long long next_row_start = (long long)(row + 1) * N - ((long long)(row + 1) * (row + 2)) / 2;
            if (idx < next_row_start) break;
            row++;
            row_start = next_row_start;
        }

        int col = (int)(idx - row_start) + row + 1;

        if (row < N && col < N && col > row) {
            C[row * N + col] = 0.0f;
        }
    }
}

torch::Tensor triangular_matmul(torch::Tensor A, torch::Tensor B) {
    TORCH_CHECK(A.is_cuda(), "A must be a CUDA tensor");
    TORCH_CHECK(B.is_cuda(), "B must be a CUDA tensor");
    TORCH_CHECK(A.is_contiguous(), "A must be contiguous");
    TORCH_CHECK(B.is_contiguous(), "B must be contiguous");

    int N = A.size(0);

    // Use PyTorch's optimized matmul (which uses cuBLAS)
    auto C = torch::mm(A, B);

    // Apply triangular mask using our kernel
    int total_elements = N * N;
    int threads = BLOCK_SIZE;
    int blocks = (total_elements + threads - 1) / threads;

    // Limit blocks to avoid overhead
    if (blocks > 65535) blocks = 65535;

    apply_tril_mask_kernel<<<blocks, threads>>>(
        C.data_ptr<float>(),
        N
    );

    return C;
}
