from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

__global__ void swish_kernel(const float* __restrict__ x, float* __restrict__ out, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = idx; i < n; i += stride) {
        float val = x[i];
        float sigmoid_val = 1.0f / (1.0f + expf(-val));
        out[i] = val * sigmoid_val;
    }
}

__global__ void swish_kernel_vec4(const float4* __restrict__ x, float4* __restrict__ out, int n4) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = idx; i < n4; i += stride) {
        float4 val = x[i];
        float4 result;

        result.x = val.x * (1.0f / (1.0f + expf(-val.x)));
        result.y = val.y * (1.0f / (1.0f + expf(-val.y)));
        result.z = val.z * (1.0f / (1.0f + expf(-val.z)));
        result.w = val.w * (1.0f / (1.0f + expf(-val.w)));

        out[i] = result;
    }
}

torch::Tensor swish_cuda(torch::Tensor x) {
    auto out = torch::empty_like(x);
    int n = x.numel();

    const int threads = 256;

    // Use vectorized kernel if n is divisible by 4
