from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Fast branchless softplus: log(1 + exp(x))
// Uses the identity: softplus(x) = max(x, 0) + log(1 + exp(-|x|))
// This avoids overflow and is more numerically stable
__device__ __forceinline__ float fast_softplus(float x) {
    float ax = fabsf(x);
    float max_val = fmaxf(x, 0.0f);
    // For very large |x|, exp(-|x|) is essentially 0
    // log(1 + very_small) ≈ very_small
    float exp_neg_ax = __expf(-ax);
    float log_term = __logf(1.0f + exp_neg_ax);
    return max_val + log_term;
}

__global__ void softplus_kernel_vec4_fast(const float4* __restrict__ input,
                                          float4* __restrict__ output,
                                          const int n4) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < n4) {
        float4 in = input[idx];
        float4 out;

        out.x = fast_softplus(in.x);
        out.y = fast_softplus(in.y);
        out.z = fast_softplus(in.z);
        out.w = fast_softplus(in.w);

        output[idx] = out;
    }
}

__global__ void softplus_kernel_tail(const float* __restrict__ input,
                                     float* __restrict__ output,
                                     const int start,
                                     const int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x + start;

    if (idx < n) {
        output[idx] = fast_softplus(input[idx]);
    }
}

