import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Kernel to compute mean and variance for each channel
// Uses parallel reduction within each block
template<int BLOCK_SIZE>
__global__ void compute_stats_kernel(
    const float* __restrict__ input,
    float* __restrict__ mean,
    float* __restrict__ var,
    int N, int C, int H, int W) {

    extern __shared__ float shared[];
    float* s_sum = shared;
    float* s_sum_sq = shared + BLOCK_SIZE;

    int c = blockIdx.x;
    int tid = threadIdx.x;

    int spatial_size = H * W;
    int total_elements = N * spatial_size;

    float local_sum = 0.0f;
    float local_sum_sq = 0.0f;

    // Each thread processes multiple elements
    for (int i = tid; i < total_elements; i += BLOCK_SIZE) {
        int n = i / spatial_size;
        int hw = i % spatial_size;
        int h = hw / W;
        int w = hw % W;

        int idx = n * C * H * W + c * H * W + h * W + w;
        float val = input[idx];
        local_sum += val;
        local_sum_sq += val * val;
    }

    s_sum[tid] = local_sum;
    s_sum_sq[tid] = local_sum_sq;
    __syncthreads();

    // Parallel reduction
    for (int stride = BLOCK_SIZE / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            s_sum[tid] += s_sum[tid + stride];
            s_sum_sq[tid] += s_sum_sq[tid + stride];
        }
        __syncthreads();
    }

    if (tid == 0) {
        float count = (float)(total_elements);
        mean[c] = s_sum[0] / count;
        var[c] = s_sum_sq[0] / count - (s_sum[0] / count) * (s_sum[0] / count);
    }
}

// Kernel to normalize the input
__global__ void normalize_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    const float* __restrict__ mean,
    const float* __restrict__ var,
    const float* __restrict__ gamma,
    const float* __restrict__ beta,
    int N, int C, int H, int W,
    float epsilon) {

    int total = N * C * H * W;
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < total) {
        int w = idx % W;
        int h = (idx / W) % H;
        int c = (idx / (W * H)) % C;

        float m = mean[c];
        float v = var[c];
        float g = gamma[c];
        float b = beta[c];

        float inv_std = rsqrtf(v + epsilon);
        output[idx] = g * (input[idx] - m) * inv_std + b;
    }
}

// Kernel to update running stats
__global__ void update_running_stats_kernel(
    float* __restrict__ running_mean,
    float* __restrict__ running_var,
    const float* __restrict__ batch_mean,
    const float* __restrict__ batch_var,
    float momentum,
    int C) {

    int c = blockIdx.x * blockDim.x + threadIdx.x;
    if (c < C) {
        running_mean[c] = (1.0f - momentum) * running_mean[c] + momentum * batch_mean[c];
        running_var[c] = (1.0f - momentum) * running_var[c] + momentum * batch_var[c];
    }
}

// Inference kernel that uses running stats
__global__ void normalize_inference_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    const float* __restrict__ running_mean,
    const float* __restrict__ running_var,
    const float* __restrict__ gamma,
    const float* __restrict__ beta,
    int N, int C, int H, int W,
    float epsilon) {

    int total = N * C * H * W;
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < total) {
        int c = (idx / (W * H)) % C;

        float m = running_mean[c];
        float v = running_var[c];
        float g = gamma[c];
        float b = beta[c];

        float inv_std = rsqrtf(v + epsilon);
        output[idx] = g * (input[idx] - m) * inv_std + b;
    }
}

torch::Tensor batch_norm_forward(
    torch::Tensor input,
    torch::Tensor gamma,
    torch::Tensor beta,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    bool training,
    float momentum,
    float epsilon) {

    int N = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);

    auto output = torch::empty_like(input);

    const int BLOCK_SIZE = 256;

    if (training) {
        // Compute batch statistics
        auto batch_mean = torch::empty({C}, input.options());
        auto batch_var = torch::empty({C}, input.options());

        // Launch stats computation kernel - one block per channel
        int shared_mem_size = 2 * BLOCK_SIZE * sizeof(float);
        compute_stats_kernel<BLOCK_SIZE><<<C, BLOCK_SIZE, shared_mem_size>>>(
            input.data_ptr<float>(),
            batch_mean.data_ptr<float>(),
