#include <cuda_runtime.h>

// Kernel: each thread handles one spatial position (b, d1, d2)
// Computes RMS across features and normalizes in-place style to output
__global__ void rms_norm_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    const int batch_size,
    const int num_features,
    const int dim1,
    const int dim2,
    const float eps
) {
    // Each thread handles one (batch, d1, d2) position
    int spatial_idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_spatial = batch_size * dim1 * dim2;

    if (spatial_idx >= total_spatial) return;

    // Decode spatial index to (b, d1_idx, d2_idx)
    int b = spatial_idx / (dim1 * dim2);
    int remainder = spatial_idx % (dim1 * dim2);
    int d1_idx = remainder / dim2;
    int d2_idx = remainder % dim2;

    // Compute sum of squares across features
    float sum_sq = 0.0f;

    // Input layout: (batch_size, num_features, dim1, dim2)
    // Stride: batch_stride = num_features * dim1 * dim2
    //         feature_stride = dim1 * dim2
    //         dim1_stride = dim2
    //         dim2_stride = 1

    int base_idx = b * (num_features * dim1 * dim2) + d1_idx * dim2 + d2_idx;
    int feature_stride = dim1 * dim2;

    for (int f = 0; f < num_features; f++) {
        float val = input[base_idx + f * feature_stride];
        sum_sq += val * val;
    }

    // Compute RMS
    float rms = sqrtf(sum_sq / num_features + eps);
    float inv_rms = 1.0f / rms;

    // Normalize and write output
    for (int f = 0; f < num_features; f++) {
        int idx = base_idx + f * feature_stride;
        output[idx] = input[idx] * inv_rms;
    }
}

