import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Warp-level reduction
__inline__ __device__ float warpReduceSum(float val) {
    for (int offset = 16; offset > 0; offset /= 2)
        val += __shfl_down_sync(0xffffffff, val, offset);
    return val;
}

// Block-level reduction using shared memory
__inline__ __device__ float blockReduceSum(float val, float* shared) {
    int lane = threadIdx.x % 32;
    int wid = threadIdx.x / 32;

    val = warpReduceSum(val);

    if (lane == 0) shared[wid] = val;
    __syncthreads();

    val = (threadIdx.x < blockDim.x / 32) ? shared[lane] : 0.0f;

    if (wid == 0) val = warpReduceSum(val);

    return val;
}

__global__ void group_norm_kernel(
    const float* __restrict__ input,
    const float* __restrict__ gamma,
    const float* __restrict__ beta,
    float* __restrict__ output,
    int batch_size,
    int num_channels,
    int num_groups,
    int spatial_size,
    float eps
) {
    extern __shared__ float shared[];

    int group_idx = blockIdx.x;
    int batch_idx = group_idx / num_groups;
    int group_id = group_idx % num_groups;

    if (batch_idx >= batch_size) return;

    int channels_per_group = num_channels / num_groups;
    int group_size = channels_per_group * spatial_size;

    int start_channel = group_id * channels_per_group;

    // Compute sum and sum of squares
    float sum = 0.0f;
    float sum_sq = 0.0f;

    for (int i = threadIdx.x; i < group_size; i += blockDim.x) {
        int local_channel = i / spatial_size;
        int spatial_idx = i % spatial_size;
        int channel = start_channel + local_channel;

        int idx = batch_idx * num_channels * spatial_size + channel * spatial_size + spatial_idx;
        float val = input[idx];
        sum += val;
        sum_sq += val * val;
    }

    // Reduce within block
    sum = blockReduceSum(sum, shared);
    __syncthreads();
    sum_sq = blockReduceSum(sum_sq, shared);
    __syncthreads();

    // Compute mean and variance
    __shared__ float mean_shared, rstd_shared;
    if (threadIdx.x == 0) {
        float mean = sum / group_size;
        float var = sum_sq / group_size - mean * mean;
        mean_shared = mean;
        rstd_shared = rsqrtf(var + eps);
    }
    __syncthreads();

    float mean = mean_shared;
    float rstd = rstd_shared;

    // Normalize and apply affine transformation
    for (int i = threadIdx.x; i < group_size; i += blockDim.x) {
        int local_channel = i / spatial_size;
        int spatial_idx = i % spatial_size;
        int channel = start_channel + local_channel;

        int idx = batch_idx * num_channels * spatial_size + channel * spatial_size + spatial_idx;
        float val = input[idx];
        float normalized = (val - mean) * rstd;
        output[idx] = normalized * gamma[channel] + beta[channel];
    }
}

torch::Tensor group_norm_cuda(
    torch::Tensor input,
    torch::Tensor gamma,
    torch::Tensor beta,
    int num_groups,
    float eps
) {
    auto batch_size = input.size(0);
    auto num_channels = input.size(1);
    int64_t spatial_size = 1;
    for (int i = 2; i < input.dim(); i++) {
        spatial_size *= input.size(i);
    }

    auto output = torch::empty_like(input);

    int num_blocks = batch_size * num_groups;
    int threads = 256;
    int shared_mem_size = (threads / 32) * sizeof(float);

    group_norm_kernel<<<num_blocks, threads, shared_mem_size>>>(
