Looking at the previous implementation, it's correct but slower than PyTorch. The main issues are:
1. Each block handles one group, but with 8 groups * 112 batches = 896 blocks, we're not utilizing the GPU well
2. The division operations (`i / spatial_size`, `i % spatial_size`) are expensive
3. Memory access patterns could be improved with vectorized loads

Let me create an optimized version using multiple blocks per group for better parallelism and vectorized memory access:

```python
import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Warp-level reduction
__inline__ __device__ float warpReduceSum(float val) {
    #pragma unroll
    for (int offset = 16; offset > 0; offset /= 2)
        val += __shfl_down_sync(0xffffffff, val, offset);
    return val;
}

__global__ void group_norm_stats_kernel(
    const float* __restrict__ input,
    float* __restrict__ mean_out,
    float* __restrict__ var_out,
    int batch_size,
    int num_channels,
    int num_groups,
    int spatial_size
) {
    extern __shared__ float shared[];
    float* s_sum = shared;
    float* s_sum_sq = shared + blockDim.x / 32;

    int group_idx = blockIdx.x;
    int batch_idx = group_idx / num_groups;
    int group_id = group_idx % num_groups;

    int channels_per_group = num_channels / num_groups;
    long group_size = (long)channels_per_group * spatial_size;
    int start_channel = group_id * channels_per_group;

    long batch_offset = (long)batch_idx * num_channels * spatial_size;
    long group_offset = batch_offset + (long)start_channel * spatial_size;

    float sum = 0.0f;
    float sum_sq = 0.0f;

    // Vectorized loads using float4
    int total_elements = channels_per_group * spatial_size;
    int vec_elements = total_elements / 4;

    const float4* input_vec = reinterpret_cast<const float4*>(input + group_offset);

    for (int i = threadIdx.x; i < vec_elements; i += blockDim.x) {
        float4 v = input_vec[i];
        sum += v.x + v.y + v.z + v.w;
        sum_sq += v.x*v.x + v.y*v.y + v.z*v.z + v.w*v.w;
    }

    // Handle remaining elements
    int remaining_start = vec_elements * 4;
    for (int i = remaining_start + threadIdx.x; i < total_elements; i += blockDim.x) {
        float val = input[group_offset + i];
        sum += val;
        sum_sq += val * val;
    }

    // Warp reduce
    sum = warpReduceSum(sum);
    sum_sq = warpReduceSum(sum_sq);

    int lane = threadIdx.x % 32;
    int wid = threadIdx.x / 32;

    if (lane == 0) {
        s_sum[wid] = sum;
        s_sum_sq[wid] = sum_sq;
    }
    __syncthreads();

    // Final reduction in first warp
    int numWarps = blockDim.x / 32;
    if (threadIdx.x < numWarps) {
        sum = s_sum[threadIdx.x];
        sum_sq = s_sum_sq[threadIdx.x];
    } else {
        sum = 0.0f;
        sum_sq = 0.0f;
    }

    if (wid == 0) {
        sum = warpReduceSum(sum);
        sum_sq = warpReduceSum(sum_sq);
    }

    if (threadIdx.x == 0) {
        float mean = sum / group_size;
        float var = sum_sq / group_size - mean * mean;
        mean_out[group_idx] = mean;
        var_out[group_idx] = var;
    }
}

__global__ void group_norm_apply_kernel(
    const float* __restrict__ input,
    const float* __restrict__ gamma,
    const float* __restrict__ beta,
    const float* __restrict__ mean,
    const float* __restrict__ var,
    float* __restrict__ output,
    int batch_size,
    int num_channels,
    int num_groups,
    int spatial_size,
    float eps
