    int group_idx = blockIdx.y;
    int batch_idx = group_idx / num_groups;
    int group_id = group_idx % num_groups;

    int channels_per_group = num_channels / num_groups;
    int start_channel = group_id * channels_per_group;

    float m = mean[group_idx];
    float rstd = rsqrtf(var[group_idx] + eps);

    long batch_offset = (long)batch_idx * num_channels * spatial_size;
    long group_offset = batch_offset + (long)start_channel * spatial_size;

    int total_elements = channels_per_group * spatial_size;
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Process 4 elements per thread when possible
    int vec_elements = total_elements / 4;

    if (idx < vec_elements) {
