    const int64_t oh = (idx / output_w) % output_h;
    const int64_t od = (idx / (output_w * output_h)) % output_d;
    const int64_t c = (idx / (output_w * output_h * output_d)) % channels;
    const int64_t b = idx / (output_w * output_h * output_d * channels);

