            vals = *reinterpret_cast<const float4*>(x + i);

            // Process each element
            float x0 = vals.x;
            float x1 = vals.y;
            float x2 = vals.z;
            float x3 = vals.w;

            float x0_cubed = x0 * x0 * x0;
            float x1_cubed = x1 * x1 * x1;
            float x2_cubed = x2 * x2 * x2;
            float x3_cubed = x3 * x3 * x3;

            float inner0 = sqrt_2_over_pi * (x0 + coeff * x0_cubed);
            float inner1 = sqrt_2_over_pi * (x1 + coeff * x1_cubed);
            float inner2 = sqrt_2_over_pi * (x2 + coeff * x2_cubed);
            float inner3 = sqrt_2_over_pi * (x3 + coeff * x3_cubed);

            results.x = 0.5f * x0 * (1.0f + tanhf(inner0));
            results.y = 0.5f * x1 * (1.0f + tanhf(inner1));
            results.z = 0.5f * x2 * (1.0f + tanhf(inner2));
            results.w = 0.5f * x3 * (1.0f + tanhf(inner3));

